import React from 'react';
import Hero from './Hero';
import About from './About';


const Landing = () => {
    return (
        <div style={{ minHeight: '88vh'}}>
            <Hero />
            <About />
            <a href="/auth/google">Sign In with Google</a>
        </div>
    )
}

export default Landing;
